import{_ as t,o as i,c as a,a3 as o}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Module Development — Developer Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Module Development — Developer Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/module-development-guide"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Module Development — Developer Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/module-development-guide"}]]},"headers":[],"relativePath":"developer-guide/module-development-guide.md","filePath":"developer-guide/module-development-guide.md","lastUpdated":1784364994000}'),s={name:"developer-guide/module-development-guide.md"};function d(n,e,r,l,c,p){return i(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="module-development-—-developer-guide" tabindex="-1">Module Development — Developer Guide <a class="header-anchor" href="#module-development-—-developer-guide" aria-label="Permalink to &quot;Module Development — Developer Guide&quot;">​</a></h1><p>Canonical checklist for building a business module. Copy the <strong>Leads</strong> module structure; do not invent a second pattern.</p><h2 id="registration-recipe" tabindex="-1">Registration recipe <a class="header-anchor" href="#registration-recipe" aria-label="Permalink to &quot;Registration recipe&quot;">​</a></h2><ol><li><strong>Catalog (production)</strong> — Ship an idempotent <strong>data migration</strong> that calls <code>App\\Support\\Catalog\\DefaultModuleRegistrar</code> (<code>slug</code>, pricing defaults, <code>status=published</code>, <code>is_default_included</code> / <code>is_billable</code>). Also keep <code>CatalogSeeder</code> in sync for <strong>local/CI fresh DBs only</strong> — never rely on <code>db:seed</code> in production. Optional: Central Modules API for non-default / commercial catalog edits.</li><li><strong>Permissions (production)</strong> — Add <code>{slug} =&gt; [view, create, update, delete, …]</code> in <code>config/tenant-permissions.php</code> and default grants in <code>config/tenant-default-role-permissions.php</code>. Ship a data migration that calls <code>TenantPermissionSynchronizer::grantMissingDefaultRolePermissions([...])</code> so existing workspaces receive grants additively. Modules never auto-grant permissions; roles do. Login never syncs RBAC.</li><li><strong>Routes</strong> — Tenant API:</li></ol><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Route</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">middleware</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth:tenant-api&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;tenant.user&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;module:{slug}&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;can:{slug}.view&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">group</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> () {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // …</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><ol start="4"><li><strong>Domain code</strong> — Flat under existing namespaces (no <code>Modules/</code> package):</li></ol><table tabindex="0"><thead><tr><th>Layer</th><th>Location</th></tr></thead><tbody><tr><td>Models</td><td><code>app/Models/</code> + <code>BelongsToTenant</code></td></tr><tr><td>Migrations</td><td><code>database/migrations/</code></td></tr><tr><td>Factories</td><td><code>database/factories/</code></td></tr><tr><td>Seeders</td><td><code>database/seeders/Tenant/</code> for local/demo only; production catalog/permission rows use <strong>data migrations</strong></td></tr><tr><td>Controllers</td><td><code>app/Http/Controllers/Tenant/Api/V1/</code></td></tr><tr><td>Form requests</td><td><code>app/Http/Requests/Tenant/Api/V1/{Module}/</code></td></tr><tr><td>Resources</td><td><code>app/Http/Resources/Tenant/Api/V1/{Module}/</code></td></tr><tr><td>Policies</td><td><code>app/Policies/</code></td></tr><tr><td>Services</td><td><code>app/Services/Tenant/</code></td></tr><tr><td>Events / Listeners</td><td><code>app/Events/</code>, <code>app/Listeners/</code></td></tr><tr><td>Notifications</td><td><code>app/Notifications/Tenant/</code></td></tr></tbody></table><ol start="5"><li><strong>Frontend</strong> — <code>src/pages/{slug}/</code>, API service, types, <code>PERMISSIONS</code> / <code>QUERY_KEYS</code>, nav item with <code>permission</code> <strong>and</strong> <code>module</code>, route under <code>TenantProtectedRoute</code>.</li><li><strong>Tests</strong> — Pest feature suite + Playwright <code>test:e2e:{slug}</code>.</li><li><strong>Docs</strong> — User / developer / production guides, API, database, CHANGELOG.</li></ol><h2 id="logging-both-required" tabindex="-1">Logging (both required) <a class="header-anchor" href="#logging-both-required" aria-label="Permalink to &quot;Logging (both required)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Mechanism</th><th>Purpose</th></tr></thead><tbody><tr><td>Audit</td><td><code>PlatformAuditService</code> → <code>activity(&#39;platform&#39;)</code></td><td>Actor, workspace, IP, UA, action for create/update/delete/assign/status changes</td></tr><tr><td>Activity</td><td>Spatie <code>LogsActivity</code> on primary model</td><td>Attribute-level change history</td></tr><tr><td>Timeline</td><td>Domain <code>*_activities</code> table (when UX needs it)</td><td>User-facing history (notes, stage moves, assignments)</td></tr></tbody></table><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h2><p>Dispatch domain events from the service layer. Listeners handle audit side-effects and notifications. Do <strong>not</strong> build per-module notification stacks outside Laravel notifications.</p><h2 id="dashboard-widgets" tabindex="-1">Dashboard widgets <a class="header-anchor" href="#dashboard-widgets" aria-label="Permalink to &quot;Dashboard widgets&quot;">​</a></h2><p>When a module contributes dashboard cards:</p><ol><li>Extend <code>App\\Services\\Tenant\\DashboardWidgetService</code> (same registry pattern as Leads/Tasks).</li><li>Gate each widget on <code>EntitlementService::hasModule</code> + the user’s Spatie permission.</li><li>Apply assignee scoping with <code>ScopesToAssignee</code> when the module uses <code>{slug}.assign</code>.</li><li>Return <code>{ id, module, permission, scope, data }</code> objects only — the SPA renders by <code>id</code>.</li><li>Do not invent a parallel dashboard API or a Calendar widget before the Calendar module.</li></ol><p>See <a href="/api/tenant-v1-dashboard">tenant-v1-dashboard.md</a>.</p><h2 id="in-app-notifications" tabindex="-1">In-app notifications <a class="header-anchor" href="#in-app-notifications" aria-label="Permalink to &quot;In-app notifications&quot;">​</a></h2><ul><li>Use Laravel notification channels required by the contract for that event (<code>database</code> plus <code>broadcast</code> for realtime in-app delivery; add <code>mail</code> only when product behavior requires it).</li><li>Implement <code>ShouldQueue</code> and use <code>App\\Notifications\\Concerns\\QueuesOnEmails</code> so jobs land on the dedicated <code>emails</code> queue (<code>php artisan queue:work --queue=emails</code>).</li><li>Persist via the standard <code>notifications</code> table; expose tenant APIs under <code>/notifications*</code> (<a href="/api/tenant-v1-notifications">tenant-v1-notifications.md</a>).</li><li>Register realtime in-app types in the SPA Notification Registry; Echo updates Query caches and polling remains a recovery path.</li><li>Schedule due/overdue fan-out through <code>crm:send-due-notifications</code> rather than ad-hoc cron per module.</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>If the module needs settings, register keys in <code>SystemSettingDefinitions</code> / <code>TenantSettingDefinitions</code> and resolve Central → Tenant → system. Do not invent a parallel settings store.</p><h2 id="billing" tabindex="-1">Billing <a class="header-anchor" href="#billing" aria-label="Permalink to &quot;Billing&quot;">​</a></h2><p>Paid modules: catalog <code>is_billable</code>, marketplace install, <code>ModuleSubscriptionService</code>, consolidated billing. Never implement independent payment flows.</p><h2 id="frontend-checklist" tabindex="-1">Frontend checklist <a class="header-anchor" href="#frontend-checklist" aria-label="Permalink to &quot;Frontend checklist&quot;">​</a></h2><ul><li>Pages, forms, tables, filters, dialogs/drawers</li><li>Shared design system (<code>PageHeader</code>, <code>DataTable</code>, <code>PermissionGate</code>, empty/error/loading states)</li><li>Nav + breadcrumbs respect <strong>installed modules</strong> and <strong>user permissions</strong></li><li>Auth payload includes active module slugs for SPA gating</li></ul><h2 id="testing-checklist" tabindex="-1">Testing checklist <a class="header-anchor" href="#testing-checklist" aria-label="Permalink to &quot;Testing checklist&quot;">​</a></h2><p><strong>Pest:</strong> unit where useful; feature CRUD; authorization; validation; tenant isolation; module middleware denial.</p><p><strong>Playwright:</strong> dedicated suite; script <code>test:e2e:{slug}</code>; independently runnable.</p><p><strong>Manual QA:</strong> Cursor browser — CRUD, search, filters, pagination, validation, authz, responsive layout, console, network.</p><h2 id="anti-patterns" tabindex="-1">Anti-patterns <a class="header-anchor" href="#anti-patterns" aria-label="Permalink to &quot;Anti-patterns&quot;">​</a></h2><ul><li>Laravel Modules / nwidart / plugin discovery</li><li>Repositories layer</li><li>Skipping <code>module:</code> or <code>can:</code> middleware</li><li>Static nav that ignores entitlements</li><li>Custom audit/notification systems outside platform services</li><li>Production <code>db:seed</code> / <code>CatalogSeeder</code> to register default modules</li><li>Login-time or dashboard-time permission “repair”</li><li><code>syncPermissions()</code> on existing customized roles during deploy</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/deployment/module-development">Production module registration</a></li><li><a href="/developer-guide/communication-templates">Communication Templates</a> — reusable platform module pattern</li><li><a href="/developer-guide/tenant-provisioning">Tenant provisioning</a></li></ul>`,32)])])}const g=t(s,[["render",d]]);export{u as __pageData,g as default};
